package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithRecordSeparator_char() {
        CSVFormat original = CSVFormat.DEFAULT;
        char separator = '\n';
        CSVFormat result = original.withRecordSeparator(separator);
        assertNotNull(result);
        assertEquals(String.valueOf(separator), result.getRecordSeparator());
        // Ensure original is unchanged (immutability)
        assertEquals(CSVFormat.DEFAULT.getRecordSeparator(), original.getRecordSeparator());
    }

    @Test
    void testWithRecordSeparator_char_differentSeparator() {
        CSVFormat original = CSVFormat.DEFAULT;
        char separator = '\r';
        CSVFormat result = original.withRecordSeparator(separator);
        assertNotNull(result);
        assertEquals(String.valueOf(separator), result.getRecordSeparator());
        assertNotSame(original, result);
    }

    @Test
    void testWithRecordSeparator_char_specialChar() {
        CSVFormat original = CSVFormat.DEFAULT;
        char separator = '\u2028'; // Unicode line separator
        CSVFormat result = original.withRecordSeparator(separator);
        assertNotNull(result);
        assertEquals(String.valueOf(separator), result.getRecordSeparator());
        assertNotSame(original, result);
    }
}
